    console.log('[AI Meal Estimate] Model:', DEFAULT_MODEL);
    console.log('[AI Meal Estimate] Prompt length:', formattedPrompt.length);

    // Call Hugging Face Inference API with timeout
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 60000); // 60 second timeout

    let hfRes;
    try {
      const requestBody = {
        inputs: formattedPrompt,
        parameters: {
          max_new_tokens: 1500,
          temperature: 0.3,
          top_p: 0.9,
          return_full_text: false,
          do_sample: true,
        },
        options: {
          wait_for_model: true,
          use_cache: false,
        },
      };

      console.log('[AI Meal Estimate] Request body prepared');

      hfRes = await fetch(`${HUGGINGFACE_BASE_URL}/${DEFAULT_MODEL}`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${HUGGINGFACE_API_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(requestBody),
        signal: controller.signal,
      });

      console.log('[AI Meal Estimate] Hugging Face response received');
      console.log('[AI Meal Estimate] Status:', hfRes.status);
      console.log('[AI Meal Estimate] Status text:', hfRes.statusText);
