      clearTimeout(timeoutId);
      console.error('[AI Meal Estimate] Fetch error:', fetchError);
      console.error('[AI Meal Estimate] Error name:', fetchError.name);
      console.error('[AI Meal Estimate] Error message:', fetchError.message);

      if (fetchError.name === "AbortError") {
        return new Response(
          JSON.stringify({
            error: "Request timeout. The AI model is taking too long to respond. Please try again.",
          }),
          {
            status: 504,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          }
        );
      }

      return new Response(
        JSON.stringify({
          error: "Failed to connect to AI service. Please check your internet connection and try again.",
          detail: fetchError.message,
        }),
        {
          status: 502,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    clearTimeout(timeoutId);

    if (!hfRes.ok) {
      const errorText = await hfRes.text();
      console.error('[AI Meal Estimate] Hugging Face API error:', hfRes.status, errorText);

      if (hfRes.status === 429) {
        return new Response(
          JSON.stringify({ error: "Rate limit exceeded. Please try again in a moment." }),
          {
            status: 429,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          }
        );
      }

      if (hfRes.status === 503) {
        return new Response(
          JSON.stringify({
            error: "Model is loading. Please wait 10-20 seconds and try again.",
          }),
          {
            status: 503,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          }
        );
      }

      return new Response(
        JSON.stringify({
          error: `AI service error (${hfRes.status}). Please try again.`,
          detail: errorText,
        }),
        {
          status: 502,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    const hfResponse = await hfRes.json();
    console.log('[AI Meal Estimate] Response parsed');
    console.log('[AI Meal Estimate] Response type:', typeof hfResponse);
    console.log('[AI Meal Estimate] Response preview:', JSON.stringify(hfResponse).substring(0, 500));

    // Extract the generated text
    let aiText = "";
    if (Array.isArray(hfResponse) && hfResponse.length > 0) {
      aiText = hfResponse[0].generated_text || "";
    } else if (hfResponse.generated_text) {
      aiText = hfResponse.generated_text;
    } else if (typeof hfResponse === "string") {
      aiText = hfResponse;
    } else if (hfResponse[0] && typeof hfResponse[0] === "string") {
      aiText = hfResponse[0];
    }

    if (!aiText) {
      console.error('[AI Meal Estimate] Empty response from Hugging Face');
      console.error('[AI Meal Estimate] Full response:', JSON.stringify(hfResponse));
      return new Response(
        JSON.stringify({
          error: "Empty response from AI service. Please try again.",
          detail: "No generated text in response",
        }),
        {
          status: 502,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    console.log('[AI Meal Estimate] AI text extracted:', aiText.substring(0, 300));

    // Try to extract JSON from the response
    const jsonMatch = aiText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      console.error('[AI Meal Estimate] No JSON found in response:', aiText);
      return new Response(
        JSON.stringify({
          error: "Invalid response format from AI service. Please try again.",
          detail: "No JSON found in AI response",
          rawResponse: aiText.substring(0, 500),
        }),
        {
          status: 502,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    // Parse the JSON response
    let parsedResponse;
    try {
      parsedResponse = JSON.parse(jsonMatch[0]);
      console.log('[AI Meal Estimate] JSON parsed successfully');
    } catch (parseError: any) {
      console.error('[AI Meal Estimate] Failed to parse JSON:', jsonMatch[0]);
      console.error('[AI Meal Estimate] Parse error:', parseError.message);
      return new Response(
        JSON.stringify({
          error: "Invalid response format from AI service. Please try again.",
          detail: "Failed to parse JSON",
          rawJson: jsonMatch[0].substring(0, 500),
        }),
        {
          status: 502,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    // Validate response structure
    if (
      !parsedResponse.assumptions ||
      !parsedResponse.items ||
      !Array.isArray(parsedResponse.items) ||
      !parsedResponse.totals
    ) {
      console.error('[AI Meal Estimate] Invalid response structure:', parsedResponse);
      return new Response(
        JSON.stringify({
          error: "Invalid response structure from AI service. Please try again.",
          detail: "Missing required fields",
        }),
        {
          status: 502,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    // Add AI model info to response
    const finalResponse = {
      ...parsedResponse,
      aiModel: `Hugging Face - ${DEFAULT_MODEL}`,
    };

    console.log('[AI Meal Estimate] Success! Items:', finalResponse.items.length);
    console.log('[AI Meal Estimate] Total calories:', finalResponse.totals.calories);

    return new Response(JSON.stringify(finalResponse), {
      status: 200,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error: any) {
    console.error('[AI Meal Estimate] Unhandled error:', error);
    console.error('[AI Meal Estimate] Error name:', error?.name);
    console.error('[AI Meal Estimate] Error message:', error?.message);
    console.error('[AI Meal Estimate] Error stack:', error?.stack);

    return new Response(
      JSON.stringify({
        error: "Internal server error",
        detail: error?.message || "Unknown error",
      }),
      {
        status: 500,
        headers: {
          "Access-Control-Allow-Origin": "*",
          "Content-Type": "application/json",
        },
      }
    );
  }
});

