import { SafeAreaView } from 'react-native-safe-area-context';
import { Stack } from 'expo-router';
import { getInitialPublishConfig, PublishConfig, validatePublishConfig } from '../utils/publishConfig';

export default function PublishScreen() {
  const [publishConfig, setPublishConfig] = useState<PublishConfig>(getInitialPublishConfig());
  const [errors, setErrors] = useState<string[]>([]);

  useEffect(() => {
    const initialConfig = getInitialPublishConfig();
    setPublishConfig(initialConfig);
  }, []);

  const handleInputChange = (field: keyof PublishConfig, value: string) => {
    setPublishConfig({ ...publishConfig, [field]: value });
  };

  const handlePublish = () => {
    const validationErrors = validatePublishConfig(publishConfig);
    setErrors(validationErrors);

    if (validationErrors.length > 0) {
      Alert.alert('Validation Error', validationErrors.join('\n'));
      return;
    }

    // TODO: Implement the actual publish API call here
    Alert.alert('Publishing...', `Name: ${publishConfig.name}, Bundle ID: ${publishConfig.bundleId}`);
  };

  return (
    <SafeAreaView style={styles.container}>
      <Stack.Screen options={{ title: 'Publish App' }} />
      <Text style={styles.label}>App Name</Text>
      <TextInput
        style={styles.input}
        value={publishConfig.name}
        onChangeText={(text) => handleInputChange('name', text)}
        placeholder="Enter app name"
      />

      <Text style={styles.label}>Bundle ID</Text>
      <TextInput
        style={styles.input}
        value={publishConfig.bundleId}
        onChangeText={(text) => handleInputChange('bundleId', text)}
        placeholder="Enter bundle ID (e.g. com.mycompany.myapp)"
      />

      {errors.length > 0 && (
        <View style={styles.errorContainer}>
          {errors.map((error, index) => (
            <Text key={index} style={styles.errorText}>{error}</Text>
          ))}
        </View>
      )}

      <Button title="Publish" onPress={handlePublish} />
    </SafeAreaView>
  );
}

