);
CREATE POLICY "Users can create their own meal items" ON meal_items FOR INSERT WITH CHECK (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);
CREATE POLICY "Users can update their own meal items" ON meal_items FOR UPDATE USING (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);
CREATE POLICY "Users can delete their own meal items" ON meal_items FOR DELETE USING (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);

-- RLS Policies for daily_summary
CREATE POLICY "Users can view their own daily summary" ON daily_summary FOR SELECT USING (user_id = auth.uid());
CREATE POLICY "Users can create their own daily summary" ON daily_summary FOR INSERT WITH CHECK (user_id = auth.uid());
CREATE POLICY "Users can update their own daily summary" ON daily_summary FOR UPDATE USING (user_id = auth.uid());
CREATE POLICY "Users can delete their own daily summary" ON daily_summary FOR DELETE USING (user_id = auth.uid());

-- Create indexes for better performance
CREATE INDEX IF NOT EXISTS idx_meals_user_date ON meals(user_id, date);
CREATE INDEX IF NOT EXISTS idx_meal_items_meal_id ON meal_items(meal_id);
CREATE INDEX IF NOT EXISTS idx_daily_summary_user_date ON daily_summary(user_id, date);
CREATE INDEX IF NOT EXISTS idx_foods_barcode ON foods(barcode) WHERE barcode IS NOT NULL;

-- Add FDC ID and data type to foods table
ALTER TABLE foods 
ADD COLUMN IF NOT EXISTS fdc_id bigint,
ADD COLUMN IF NOT EXISTS data_type text;

-- Add index on fdc_id for faster lookups
CREATE INDEX IF NOT EXISTS idx_foods_fdc_id ON foods(fdc_id);

-- Add comment
COMMENT ON COLUMN foods.fdc_id IS 'FoodData Central ID for foods from USDA database';
COMMENT ON COLUMN foods.data_type IS 'FDC data type: Branded, Foundation, Survey (FNDDS), SR Legacy';

-- Create my_meals table
create table my_meals (
  id uuid primary key default gen_random_uuid(),
