import { serve } from "https://deno.land/std@0.224.0/http/server.ts";
import { GoogleGenAI } from "npm:@google/genai";

const CORS_HEADERS = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS"
};

serve(async (req) => {
  // CORS preflight
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: CORS_HEADERS });
  }

  if (req.method !== "POST") {
    return new Response(
      JSON.stringify({ error: "Method not allowed" }),
      { status: 405, headers: { "content-type": "application/json", ...CORS_HEADERS } }
    );
  }

  try {
    const { description, image } = await req.json();

    if (!description) {
      return new Response(
        JSON.stringify({ error: "Description is required" }),
        { status: 400, headers: { "content-type": "application/json", ...CORS_HEADERS } }
      );
    }

    console.log("[Gemini] Processing meal estimation request");
    console.log("[Gemini] Description:", description);
    console.log("[Gemini] Has image:", !!image);

    // Initialize Gemini AI
    const apiKey = Deno.env.get("GEMINI_API_KEY");
    if (!apiKey) {
      console.error("[Gemini] API key not configured");
      return new Response(
        JSON.stringify({ error: "AI service not configured" }),
        { status: 500, headers: { "content-type": "application/json", ...CORS_HEADERS } }
      );
    }

    const ai = new GoogleGenAI({ apiKey });
    const model = "gemini-2.5-flash";

    // Build the prompt
    const systemPrompt = `You are a nutrition estimator. Your task is to analyze meal descriptions and return detailed nutritional information in JSON format.

Rules:
1. Break down the meal into individual ingredients
2. Estimate the quantity in grams for each ingredient
3. Calculate calories and macros (protein, carbs, fat, fiber) for each ingredient
4. If details are missing, make reasonable assumptions and list them
5. If you need clarification, include questions in the response
6. If the user says "no rice" or similar, exclude that ingredient
7. Return ONLY valid JSON, no markdown or extra text

Required JSON format:
{
  "meal_name": "string",
  "assumptions": ["string"],
  "questions": ["string"],
  "ingredients": [
    {
      "name": "string",
      "quantity": "string (e.g., '1 cup', '150g')",
      "grams": number,
      "calories": number,
      "protein_g": number,
      "carbs_g": number,
      "fat_g": number,
      "fiber_g": number
    }
  ],
  "totals": {
    "calories": number,
    "protein_g": number,
    "carbs_g": number,
    "fat_g": number,
    "fiber_g": number
  }
}`;

    // Prepare content parts
    const parts: any[] = [
      { text: systemPrompt },
      { text: `\n\nUser's meal description: ${description}` }
    ];

    // Add image if provided
    if (image) {
      console.log("[Gemini] Adding image to request");
      // Extract base64 data from data URL
      const base64Match = image.match(/^data:([^;]+);base64,(.+)$/);
      if (base64Match) {
        const mimeType = base64Match[1];
        const base64Data = base64Match[2];
        parts.push({
          inlineData: {
            data: base64Data,
            mimeType: mimeType
          }
        });
      }
    }

    console.log("[Gemini] Calling Gemini API...");

    // Call Gemini API
    const response = await ai.models.generateContent({
      model,
      contents: [{ role: "user", parts }]
    });

    console.log("[Gemini] Response received");

    // Extract text from response
    const candidate = response.candidates?.[0];
    const textParts = candidate?.content?.parts ?? [];
    const text = textParts.map((p: any) => p?.text).filter(Boolean).join("\n").trim();

    if (!text) {
      console.error("[Gemini] No text in response");
      return new Response(
        JSON.stringify({ error: "No response from AI model" }),
        { status: 502, headers: { "content-type": "application/json", ...CORS_HEADERS } }
      );
    }

    console.log("[Gemini] Raw response:", text);

    // Parse JSON from response (handle markdown code blocks)
    let jsonText = text;
    const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (jsonMatch) {
      jsonText = jsonMatch[1].trim();
    }

    let result;
    try {
      result = JSON.parse(jsonText);
    } catch (parseError) {
      console.error("[Gemini] Failed to parse JSON:", parseError);
      console.error("[Gemini] Raw text:", text);
      return new Response(
        JSON.stringify({ error: "Failed to parse AI response. Please try again." }),
        { status: 500, headers: { "content-type": "application/json", ...CORS_HEADERS } }
      );
    }

    // Validate response structure
    if (!result.meal_name || !result.ingredients || !Array.isArray(result.ingredients) || !result.totals) {
      console.error("[Gemini] Invalid response structure:", result);
      return new Response(
        JSON.stringify({ error: "Invalid response structure from AI" }),
        { status: 500, headers: { "content-type": "application/json", ...CORS_HEADERS } }
      );
    }

    // Ensure assumptions and questions are arrays
    if (!Array.isArray(result.assumptions)) {
      result.assumptions = [];
    }
    if (!Array.isArray(result.questions)) {
      result.questions = [];
    }

    console.log("[Gemini] Estimation successful");
    console.log("[Gemini] Meal:", result.meal_name);
    console.log("[Gemini] Ingredients:", result.ingredients.length);

    return new Response(
      JSON.stringify(result),
      { status: 200, headers: { "content-type": "application/json", ...CORS_HEADERS } }
    );

  } catch (error: any) {
    console.error("[Gemini] Error:", error);
    return new Response(
      JSON.stringify({ error: error.message || "Internal server error" }),
      { status: 500, headers: { "content-type": "application/json", ...CORS_HEADERS } }
    );
  }
});

