import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { GoogleGenAI } from "npm:@google/genai";

const CORS_HEADERS = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS"
};

const TIMEOUT_MS = 20000; // 20 seconds

Deno.serve(async (req) => {
  console.log("[AI] ========================================");
  console.log("[AI] function hit");
  console.log("[AI] Request method:", req.method);
  console.log("[AI] Request URL:", req.url);
  console.log("[AI] ========================================");

  // Handle CORS preflight
  if (req.method === "OPTIONS") {
    console.log("[AI] Handling CORS preflight");
    return new Response("ok", { headers: CORS_HEADERS });
  }

  if (req.method !== "POST") {
    console.log("[AI] Method not allowed:", req.method);
    return new Response(
      JSON.stringify({ error: "Method not allowed" }),
      {
        status: 405,
        headers: { "Content-Type": "application/json", ...CORS_HEADERS }
      }
    );
  }

  try {
    // Parse request body
    const body = await req.json();
    const textPrompt = body.textPrompt || "";
    const imageBase64 = body.imageBase64 || null;

    console.log("[AI] ========================================");
    console.log("[AI] Request parsed successfully");
    console.log("[AI] text:", textPrompt);
    console.log("[AI] text length:", textPrompt.length);
    console.log("[AI] has image:", !!imageBase64);
    if (imageBase64) {
      console.log("[AI] image size:", imageBase64.length, "chars");
    }
    console.log("[AI] ========================================");

    // Validate input
    if (!textPrompt || textPrompt.trim() === "") {
      console.log("[AI] Validation failed: Missing meal description");
      return new Response(
        JSON.stringify({ error: "Missing meal description" }),
        {
          status: 400,
          headers: { "Content-Type": "application/json", ...CORS_HEADERS }
        }
      );
    }

    // Check for API key - READ ONLY FROM SERVER ENVIRONMENT
    // Try both GOOGLE_AI_API_KEY and GEMINI_API_KEY for compatibility
    const apiKey = Deno.env.get("GOOGLE_AI_API_KEY") || Deno.env.get("GEMINI_API_KEY");
    console.log("[AI] Checking for GOOGLE_AI_API_KEY or GEMINI_API_KEY...");
    console.log("[AI] API key present:", !!apiKey);

    if (!apiKey) {
      console.error("[AI] ❌ CRITICAL: GOOGLE_AI_API_KEY not configured in environment");
      console.error("[AI] Please set GOOGLE_AI_API_KEY in Supabase Edge Function secrets");
      return new Response(
        JSON.stringify({ error: "Missing GOOGLE_AI_API_KEY" }),
        {
          status: 500,
          headers: { "Content-Type": "application/json", ...CORS_HEADERS }
        }
      );
    }

    console.log("[AI] ========================================");
    console.log("[AI] API key validated successfully");
    console.log("[AI] Preparing to call Gemini API using @google/genai SDK...");
    console.log("[AI] ========================================");

    // Initialize Google AI client
    const ai = new GoogleGenAI({ apiKey });

    // System instruction to force JSON-only output
    const systemInstruction = `You are a nutrition expert. Analyze the meal description and return ONLY valid JSON matching this exact schema:

{
  "items": [
    {
      "name": "string",
      "serving": "string (e.g., '1 cup', '150g')",
      "grams": number | null,
      "calories": number,
      "protein_g": number,
      "carbs_g": number,
      "fat_g": number,
      "fiber_g": number
    }
  ],
  "total": {
    "calories": number,
    "protein_g": number,
    "carbs_g": number,
    "fat_g": number,
    "fiber_g": number
  },
  "assumptions": ["string"],
  "confidence": number (0-1),
  "follow_up_questions": ["string"]
}

Rules:
1. Break down the meal into individual ingredients
2. Estimate the quantity in grams for each ingredient (or null if not applicable)
3. Calculate calories and macros (protein, carbs, fat, fiber) for each ingredient
4. If details are missing, make reasonable assumptions and list them
5. If you need clarification, include questions in follow_up_questions
6. If the user says "no rice" or similar, exclude that ingredient
7. Return ONLY valid JSON, no markdown, no commentary, no extra text`;

    // Prepare parts for Gemini
    const parts: any[] = [
      { text: `${systemInstruction}\n\nUser's meal description: ${textPrompt}` }
    ];

    // Add image if provided
    if (imageBase64) {
      console.log("[AI] Adding image to Gemini request");

      // Extract base64 data from data URL if needed
      const base64Match = imageBase64.match(/^data:([^;]+);base64,(.+)$/);
      if (base64Match) {
        const mimeType = base64Match[1];
        const base64Data = base64Match[2];
        console.log("[AI] Image mime type:", mimeType);
        console.log("[AI] Image data length:", base64Data.length);

        parts.push({
          inlineData: {
            data: base64Data,
            mimeType: mimeType
          }
        });
      } else {
        // Assume it's already base64 without the data URL prefix
        console.log("[AI] Image data (assuming image/jpeg)");
