            result.confidence = 0.7; // Default confidence
          }
          if (!Array.isArray(result.follow_up_questions)) {
            result.follow_up_questions = [];
          }

          console.log("[AI] ========================================");
          console.log("[AI] ✅ Estimation successful!");
          console.log("[AI] Items:", result.items.length);
          console.log("[AI] Total calories:", result.total.calories);
